// Convertir el archivo binario a base64
const binaryData = $input.first().binary.file;
const base64Data = binaryData.data;

// Crear el payload para Mistral OCR
const payload = {
  model: "pixtral-12b-2409",
  messages: [
    {
      role: "user",
      content: [
        {
          type: "text",
          text: "Extract all the text from this image using OCR. Return only the extracted text without any additional formatting or explanations."
        },
        {
          type: "image_url",
          image_url: {
            url: `data:${binaryData.mimeType};base64,${base64Data}`
          }
        }
      ]
    }
  ]
};

return { payload };

// Procesar la respuesta de Mistral OCR
const response = $input.first().json;

if (!response || !response.choices || !response.choices[0]) {
  return {
    success: false,
    error: 'Invalid response from Mistral OCR',
    raw_response: JSON.stringify(response)
  };
}

const extractedText = response.choices[0].message.content;

if (!extractedText) {
  return {
    success: false,
    error: 'No text extracted from the image',
    raw_response: JSON.stringify(response)
  };
}

// Crear respuesta formateada
const result = {
  success: true,
  timestamp: new Date().toISOString(),
  extracted_text: extractedText,
  text_stats: {
    character_count: extractedText.length,
    word_count: extractedText.split(/\s+/).filter(word => word.length > 0).length,
    line_count: extractedText.split('\n').length
  },
  processing_info: {
    model: response.model || 'pixtral-12b-2409',
    usage: response.usage || null
  },
  raw_response: JSON.stringify(response)
};

return result;

// Manejar errores
const error = $input.first();

const errorResponse = {
  success: false,
  timestamp: new Date().toISOString(),
  error: {
    message: error.message || 'OCR processing failed',
    type: 'OCR_ERROR',
    details: error.error || 'Unknown error occurred during OCR processing'
  },
  raw_response: JSON.stringify(error)
};

return errorResponse;
